import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.util.LinkedHashMap;
import java.util.Map;

public class AfipRequest {
    public static void main(String[] args) throws Exception {
        // Configuración del cliente HTTP
        HttpClient client = HttpClient.newHttpClient();

        // Preparar los datos de la solicitud
        Map<String, Object> authParams = new LinkedHashMap<>();
        authParams.put("token", "your_token_here");
        authParams.put("sign", "your_sign_here");
        authParams.put("cuitRepresentada", "20409378472");

        Map<String, Object> params = new LinkedHashMap<>();
        params.put("authRequest", authParams);
        params.put("cuitConsultada", "cuit_del_cliente");

        Map<String, Object> requestMap = new LinkedHashMap<>();
        requestMap.put("environment", "dev");
        requestMap.put("method", "consultarDatosPadron");
        requestMap.put("wsid", "ws_sr_constancia_inscripcion");
        requestMap.put("params", params);

        // Convertir el mapa a JSON
        String requestBody = new com.google.gson.Gson().toJson(requestMap);

        // Crear la solicitud HTTP
        HttpRequest request = HttpRequest.newBuilder()
                .uri(new URI("https://app.afipsdk.com/api/v1/afip/requests"))
                .header("Content-Type", "application/json")
                .POST(HttpRequest.BodyPublishers.ofString(requestBody))
                .build();

        // Enviar la solicitud y obtener la respuesta
        HttpResponse<String> response = client.send(request, HttpResponse.BodyHandlers.ofString());

        // Procesar la respuesta
        if (response.statusCode() >= 400) {
            System.out.println("Error en la solicitud: " + response.body());
        } else {
            System.out.println("Respuesta: " + response.body());
        }
    }
}
